    sm[N-1] = nums[N-1]
    for i := N - 2; i >= 0; i-- {
        if nums[i] > sm[i+1] {
            sm[i] = nums[i]
        } else {
            sm[i] = sm[i+1]
        }
    }

    // 3. Determine valid elements
    result := make([]Int64, 0, N)

    for i := 0; i < N; i++ {
        isValid := false

        // Endpoints are always valid
        if i == 0 || i == N-1 {
            isValid = true
        } else {
            // Check Condition 1: Strictly greater than left side max
            // Max left is PM[i-1]
            leftMax := pm[i-1]
