    std::vector<long long> p_max(n);
    p_max[0] = nums[0];
    for (int i = 1; i < n; ++i) {
        p_max[i] = std::max(p_max[i-1], nums[i]);
    }

    // 2. Precalculate Suffix Maximums
    // SMax[i] stores max(nums[i]...nums[n-1])
    std::vector<long long> s_max(n);
    s_max[n - 1] = nums[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        s_max[i] = std::max(s_max[i+1], nums[i]);
